(function () {
  'use strict';

  function escape(value) {
    return String(value == null ? '' : value)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }

  function unescape(value) {
    return String(value == null ? '' : value)
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, '\'')
      .replace(/&amp;/g, '&');
  }

  var api = {
    escape: escape,
    unescape: unescape
  };

  window.htmlEscaper = api;
  window.escapeHtml = escape;
  window.unescapeHtml = unescape;
})();
